1	import { describe, it, expect } from "vitest";
2	import { processScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // === QUOTE: Base premiums ===
6	  it("returns premium of 5 G for an empty item list (processing fee only)", () => {
7	    const scenario = {
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote" as const, items: [] }],
10	    };
11	    const result = processScenario(scenario);
12	    expect(result).toEqual({ results: [{ premium: 5 }] });
13	  });
14	  it("calculates base premium of 100 G + 5 G fee for a single sword", () => {
15	    const scenario = {
16	      customer: { yearsWithMHPCO: 0 },
17	      steps: [{
18	        op: "quote" as const,
19	        items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
20	      }],
21	    };
22	    const result = processScenario(scenario);
23	    expect(result).toEqual({ results: [{ premium: 105 }] });
24	  });
25	  it("calculates base premium for each item type (amulet 60, staff 80, potion 40)", () => {
26	    const makeScenario = (type: string) => ({
27	      customer: { yearsWithMHPCO: 0 },
28	      steps: [{ op: "quote" as const, items: [{ type, material: "steel", enchantment: 0, cursed: false }] }],
29	    });
30	    expect(processScenario(makeScenario("amulet"))).toEqual({ results: [{ premium: 65 }] });
31	    expect(processScenario(makeScenario("staff"))).toEqual({ results: [{ premium: 85 }] });
32	    expect(processScenario(makeScenario("potion"))).toEqual({ results: [{ premium: 45 }] });
33	  });
34	  it("calculates base premium of 25 G per component (rune/moonstone)", () => {
35	    const scenario = {
36	      customer: { yearsWithMHPCO: 0 },
37	      steps: [{
38	        op: "quote" as const,
39	        items: [
40	          { type: "rune" },
41	          { type: "rune" },
42	        ],
43	      }],
44	    };
45	    const result = processScenario(scenario);
46	    expect(result).toEqual({ results: [{ premium: 55 }] });
47	  });
48	  it("applies building block discount: 3 alike components cost 60 G instead of 75 G", () => {
49	    const scenario = {
50	      customer: { yearsWithMHPCO: 0 },
51	      steps: [{
52	        op: "quote" as const,
53	        items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }],
54	      }],
55	    };
56	    const result = processScenario(scenario);
57	    expect(result).toEqual({ results: [{ premium: 65 }] });
58	  });
59	  it.todo("does not apply block discount for 4 alike components (block requires exactly 3)");
60	  it.todo("calculates mixed components without block (2 runes + 1 moonstone = 75 G)");
61	  it.todo("applies two separate blocks for 3 runes + 3 moonstones = 120 G");
62	  it.todo("sums base premiums for multiple different items in a policy");
63	
64	  // === QUOTE: Item-specific modifiers ===
65	  it.todo("adds 50% cursed surcharge to the cursed item's base premium only");
66	  it.todo("adds 30% high-enchantment surcharge for enchantment level >= 5");
67	  it.todo("applies both cursed and high-enchantment surcharges to same item");
68	  it.todo("applies item-specific surcharges only to affected items in multi-item policy");
69	
70	  // === QUOTE: Policy-wide modifiers ===
71	  it.todo("applies 10% first insurance surcharge to policy base premium");
72	  it.todo("applies 20% loyalty discount for customers with >= 2 years");
73	  it.todo("applies 15% follow-up discount on second and subsequent contracts");
74	  it.todo("combines all modifiers: newcomer with cursed sword = 165 G");
75	  it.todo("combines all modifiers: long-standing customer second contract cursed enchanted sword = 160 G");
76	
77	  // === QUOTE: Rounding ===
78	  it.todo("rounds premiums up (in MHPCO's favor)");
79	
80	  // === QUOTE: Errors ===
81	  it.todo("rejects unknown item type with non-zero exit");
82	
83	  // === CLAIM: Standard reimbursement ===
84	  it.todo("reimburses full damage minus 100 G deductible for regular item");
85	  it.todo("applies deductible per damaged item in multi-damage event");
86	  it.todo("reimburses component damage minus deductible");
87	
88	  // === CLAIM: Special clauses ===
89	  it.todo("reimburses enchantment >= 8 damage at 50% then deductible");
90	  it.todo("reimburses dragon material damage fully then deductible");
91	  it.todo("when both dragon and enchantment >= 8 apply, 50% rule wins then deductible");
92	  it.todo("dragon material with enchantment < 8 gets full reimbursement then deductible");
93	
94	  // === CLAIM: Cap ===
95	  it.todo("caps total payout at 2x insurance sum");
96	  it.todo("tracks remaining cap across multiple claims on same policy");
97	  it.todo("reduces payout to remaining cap when cap is nearly exhausted");
98	
99	  // === CLAIM: Errors ===
100	  it.todo("rejects damage to item not covered by policy");
101	  it.todo("rejects more damage entries of a type than policy covers");
102	  it.todo("rejects negative damage amount");
103	
104	  // === CLI integration ===
105	  it.todo("processes a full scenario with quote and claim steps via CLI JSON interface");
106	});
