1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUMS: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	  rune: 25,
9	  moonstone: 25,
10	};
11	
12	const itemBasePremium = (item: any): number =>
13	  BASE_PREMIUMS[item.type] ?? 0;
14	
15	const COMPONENT_TYPES = ["rune", "moonstone"];
16	const BLOCK_SIZE = 3;
17	const BLOCK_PREMIUM = 60;
18	
19	const calculateQuotePremium = (items: any[]): number => {
20	  let premium = 0;
21	  const componentCounts: Record<string, number> = {};
22	  for (const item of items) {
23	    if (COMPONENT_TYPES.includes(item.type)) {
24	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
25	    } else {
26	      premium += itemBasePremium(item);
27	    }
28	  }
29	  for (const type of Object.keys(componentCounts)) {
30	    const count = componentCounts[type];
31	    if (count === BLOCK_SIZE) {
32	      premium += BLOCK_PREMIUM;
33	    } else {
34	      premium += count * 25;
35	    }
36	  }
37	  return premium + PROCESSING_FEE;
38	};
39	
40	export function processScenario(scenario: any): any {
41	  const results = scenario.steps.map((step: any) => ({
42	    premium: calculateQuotePremium(step.items),
43	  }));
44	  return { results };
45	}
